/**
 * @summary Get equipment list, optionally filtered by area
 */
export const getGetEquipmentUrl = (params?: GetEquipmentParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/equipment?${stringifiedParams}`
    : `/api/equipment`;
};

export const getEquipment = async (
  params?: GetEquipmentParams,
  options?: RequestInit,
): Promise<EquipmentCatalog> => {
  return customFetch<EquipmentCatalog>(getGetEquipmentUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getGetEquipmentQueryKey = (params?: GetEquipmentParams) => {
  return [`/api/equipment`, ...(params ? [params] : [])] as const;
};

export const getGetEquipmentQueryOptions = <
  TData = Awaited<ReturnType<typeof getEquipment>>,
  TError = ErrorType<unknown>,
>(
  params?: GetEquipmentParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getEquipment>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getGetEquipmentQueryKey(params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getEquipment>>> = ({
    signal,
  }) => getEquipment(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof getEquipment>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetEquipmentQueryResult = NonNullable<
  Awaited<ReturnType<typeof getEquipment>>
>;
export type GetEquipmentQueryError = ErrorType<unknown>;

/**
 * @summary Get equipment list, optionally filtered by area
 */

export function useGetEquipment<
  TData = Awaited<ReturnType<typeof getEquipment>>,
  TError = ErrorType<unknown>,
>(
  params?: GetEquipmentParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getEquipment>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetEquipmentQueryOptions(params, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}
